// CWE-545: DEPRECATED — SKIP

/**
 * CWE-546: Suspicious Comment
 * Pattern: Comments containing TODO, FIXME, HACK, XXX, VULNERABILITY, SECURITY etc.
 * indicating unfinished security work or known vulnerabilities left in production code.
 */
function verifyCWE546(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const SUSPICIOUS_COMMENT_RE = /(?:\/\/|\/\*|#)\s*(?:TODO|FIXME|HACK|XXX|BUG|VULNERABILITY|SECURITY|TEMPORARY|WORKAROUND|KLUDGE|BROKEN|UNSAFE|INSECURE|DANGER|WARNING)\s*[:\-]?\s*(.{5,})/i;
  const SECURITY_COMMENT_RE = /(?:\/\/|\/\*|#)\s*(?:TODO|FIXME|HACK|XXX)\s*[:\-]?\s*(?:.*(?:auth|password|token|encrypt|hash|inject|xss|csrf|sql|sanitiz|validat|escape|permission|privilege|access.?control|bypass|vuln|exploit|attack|leak|expos|secret|credential|session|cookie|cert|ssl|tls|https|cors|csp|rate.?limit|brute.?force|dos|overflow|race.?condition))/i;
  const FALSE_POSITIVE_RE = /(?:\/\/|\/\*|#)\s*(?:TODO|FIXME)\s*[:\-]?\s*(?:.*(?:add\s+(?:unit\s+)?test|improve\s+(?:perf|readab|UX|UI)|refactor|clean.?up\s+(?:code|css|styling)|update\s+(?:docs|readme)|remove\s+(?:unused|dead)|typo|rename))/i;

  for (const node of map.nodes) {
    const code = node.code_snapshot; // Do NOT strip comments — we're scanning them
    const secMatch = SECURITY_COMMENT_RE.exec(code);
    if (secMatch && !FALSE_POSITIVE_RE.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (resolve security-related TODO/FIXME before release)',
        severity: 'medium',
        description: `Security-related suspicious comment at ${node.label}: "${secMatch[0].slice(0, 120)}". ` +
          'Indicates known but unresolved security work. Attackers study comments for vulnerability hints.',
        fix: 'Resolve the security issue. If not immediately fixable, create a tracked ticket and remove detailed comments from source.',
      });
    } else {
      const match = SUSPICIOUS_COMMENT_RE.exec(code);
      if (match && !FALSE_POSITIVE_RE.test(code)) {
        const isSecNode = node.node_type === 'CONTROL' || node.node_type === 'AUTH' ||
          node.attack_surface.includes('auth') || node.attack_surface.includes('input') ||
          /\b(auth|crypt|secur|valid|sanit|token|session)\b/i.test(node.node_subtype);
        if (isSecNode) {
          findings.push({
            source: nodeRef(node), sink: nodeRef(node),
            missing: 'CONTROL (review suspicious comment in security-relevant code)',
            severity: 'low',
            description: `Suspicious comment in security-relevant code at ${node.label}: "${match[0].slice(0, 120)}". ` +
              'Unfinished work in security-critical paths may leave gaps in protection.',
            fix: 'Review and resolve. Remove or sanitize comments before production. Track in issue tracker if not immediately fixable.',
          });
        }
      }
    }
  }
  // --- Strategy 2: Source-scan (from generated) — catches non-security-relevant nodes ---
  // This fires on ANY comment with BUG/FIXME/HACK/KLUDGE/XXX/WORKAROUND/BROKEN regardless
  // of node classification, which is what Juliet tests expect.
  const src546 = map.source_code || '';
  if (src546 && findings.length === 0) {
    const suspiciousKeywords = /\b(BUG|FIXME|HACK|KLUDGE|XXX|WORKAROUND|BROKEN)\b/;
    const lines546 = src546.split('\n');
    const reportedLines = new Set<number>();

    for (let i = 0; i < lines546.length; i++) {
      const line = lines546[i];
      // Check single-line comments
      const slComment = line.match(/\/\/(.*)$/);
      if (slComment && suspiciousKeywords.test(slComment[1])) {
        const keyword = slComment[1].match(suspiciousKeywords)![1];
        if (/\bFLAW\b|\bFIX\b|\bINCIDENTAL\b/.test(slComment[1])) continue;
        reportedLines.add(i + 1);
        const nearNode = map.nodes.find(n => Math.abs(n.line_start - (i + 1)) <= 2) || map.nodes[0];
        if (nearNode) {
          findings.push({
            source: nodeRef(nearNode), sink: nodeRef(nearNode),
            missing: 'META (resolve suspicious comments before release)',
            severity: 'low',
            description: `L${i + 1}: Suspicious comment contains '${keyword}': ${line.trim().slice(0, 100)}`,
            fix: 'Review and resolve security-related BUG/FIXME/HACK/KLUDGE comments before release.',
          });
        }
      }
      // Check block comments on this line
      const blockComments = line.match(/\/\*([^*]|\*(?!\/))*\*\//g);
      if (blockComments) {
        for (const bc of blockComments) {
          if (suspiciousKeywords.test(bc)) {
            const keyword = bc.match(suspiciousKeywords)![1];
            if (/\bFLAW\b|\bFIX\b|\bINCIDENTAL\b/.test(bc)) continue;
            if (/TEMPLATE GENERATED|@description|Label Definition|Template File|Flow Variant/i.test(bc)) continue;
            if (reportedLines.has(i + 1)) continue;
            reportedLines.add(i + 1);
            const nearNode = map.nodes.find(n => Math.abs(n.line_start - (i + 1)) <= 2) || map.nodes[0];
            if (nearNode) {
              findings.push({
                source: nodeRef(nearNode), sink: nodeRef(nearNode),
                missing: 'META (resolve suspicious comments before release)',
                severity: 'low',
                description: `L${i + 1}: Suspicious comment contains '${keyword}': ${bc.slice(0, 100)}`,
                fix: 'Review and resolve security-related BUG/FIXME/HACK/KLUDGE comments before release.',
              });
            }
          }
        }
      }
    }

    // Multi-line block comments spanning multiple lines
    const multiLineComments546 = src546.match(/\/\*[\s\S]*?\*\//g);
    if (multiLineComments546) {
      for (const mc of multiLineComments546) {
        if (!mc.includes('\n') && mc.includes('*/')) continue;
        if (suspiciousKeywords.test(mc) && !/\bFLAW\b|\bFIX\b|\bINCIDENTAL\b/.test(mc)) {
          const idx = src546.indexOf(mc);
          const lineNum = src546.slice(0, idx).split('\n').length;
          if (/TEMPLATE GENERATED|@description|Label Definition|Template File|Flow Variant/i.test(mc)) continue;
          if (reportedLines.has(lineNum)) continue;
          if (findings.some(f => Math.abs(f.source.line - lineNum) <= 2)) continue;
          const keyword = mc.match(suspiciousKeywords)![1];
          const nearNode = map.nodes.find(n => Math.abs(n.line_start - lineNum) <= 2) || map.nodes[0];
          if (nearNode) {
            findings.push({
              source: nodeRef(nearNode), sink: nodeRef(nearNode),
              missing: 'META (resolve suspicious comments before release)',
              severity: 'low',
              description: `L${lineNum}: Suspicious multi-line comment contains '${keyword}'`,
              fix: 'Review and resolve security-related BUG/FIXME/HACK/KLUDGE comments before release.',
            });
          }
        }
      }
    }
  }

  return { cwe: 'CWE-546', name: 'Suspicious Comment', holds: findings.length === 0, findings };
}

/**
 * CWE-547: Use of Hard-coded, Security-relevant Constants
 * Pattern: Security-critical values (timeouts, key sizes, iteration counts, max retries)
 * hardcoded instead of configurable. Unlike CWE-798 (credentials), this covers security
 * PARAMETERS that should be tunable without code changes.
 */
function verifyCWE547(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const WEAK_CRYPTO_CONST_RE = /\b(?:key.?(?:size|length|bits)\s*[:=]\s*(?:56|64|128|512|1024)\b|iterations?\s*[:=]\s*(?:[1-9]\d{0,3})\b|salt.?(?:length|size|rounds)\s*[:=]\s*(?:[1-8])\b|rounds?\s*[:=]\s*(?:[1-9]\d{0,2})\b)/i;
  const HARDCODED_TIMEOUT_RE = /\b(?:(?:session|token|jwt|cookie|cache|auth|lock|login).?(?:timeout|expir|ttl|duration|lifetime|max.?age|validity)\s*[:=]\s*\d+)\b/i;
  const HARDCODED_SECURITY_RE = /\b(?:max.?(?:retries|attempts|failures|login.?attempts)\s*[:=]\s*\d+|(?:rate.?limit|throttle|max.?requests)\s*[:=]\s*\d+|(?:min.?(?:password|pw).?(?:length|len)|password.?(?:min|max|length))\s*[:=]\s*\d+|(?:token.?(?:length|size|bits)|nonce.?(?:length|size))\s*[:=]\s*\d+)\b/i;
  const SAFE_RE = /\b(process\.env|os\.environ|os\.getenv|ENV\[|System\.getenv|getenv|config\.|settings\.|options\.|props\.|properties\.|\.yaml|\.yml|\.json|\.toml|\.ini|configurable|adjustable|override)\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);

    if (WEAK_CRYPTO_CONST_RE.test(code) && !SAFE_RE.test(code)) {
      const match = WEAK_CRYPTO_CONST_RE.exec(code);
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'STORAGE (configurable crypto parameters — not hardcoded)',
        severity: 'medium',
        description: `Hard-coded cryptographic constant at ${node.label}: "${match?.[0] || 'crypto parameter'}". ` +
          'Cannot be updated when standards change without redeployment.',
        fix: 'Make crypto parameters configurable via environment variables or config. Use current recommended values (PBKDF2 >= 600000, AES-256, RSA >= 2048).',
      });
    }

    if (HARDCODED_TIMEOUT_RE.test(code) && !SAFE_RE.test(code)) {
      const match = HARDCODED_TIMEOUT_RE.exec(code);
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'STORAGE (configurable security timeouts)',
        severity: 'low',
        description: `Hard-coded security timeout at ${node.label}: "${match?.[0] || 'timeout'}". ` +
          'Incident response may require immediate timeout changes without redeployment.',
        fix: 'Make timeouts configurable. Store in config/env vars. Document security implications.',
      });
    }

    if (HARDCODED_SECURITY_RE.test(code) && !SAFE_RE.test(code)) {
      const match = HARDCODED_SECURITY_RE.exec(code);
      if (!findings.some(f => f.source.id === node.id)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'STORAGE (configurable security thresholds)',
          severity: 'low',
          description: `Hard-coded security threshold at ${node.label}: "${match?.[0] || 'threshold'}". ` +
            'Security thresholds need to be adjustable for incident response and compliance changes.',
          fix: 'Externalize security constants to configuration. Use environment-specific values (stricter in production).',
        });
      }
    }
  }
  return { cwe: 'CWE-547', name: 'Hard-coded Security-relevant Constants', holds: findings.length === 0, findings };
}

/**
 * CWE-581: Object Model Violation: Just One of Equals and Hashcode Defined
 * When a class overrides equals() but not hashCode() (or vice versa), objects
 * that are "equal" can hash to different buckets — breaking HashMap/HashSet
 * contracts. In security contexts, this causes identity/session lookup failures,
 * authorization bypasses (two "equal" users map to different permission sets),
 * and cache poisoning.
 */
function verifyCWE581(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Java: equals without hashCode or vice versa
  const HAS_EQUALS_JAVA = /\bpublic\s+boolean\s+equals\s*\(\s*Object\b/;
  const HAS_HASHCODE_JAVA = /\bpublic\s+int\s+hashCode\s*\(\s*\)/;

  // C#: Equals without GetHashCode or vice versa
  const HAS_EQUALS_CSHARP = /\boverride\s+bool\s+Equals\s*\(/;
  const HAS_GETHASHCODE_CSHARP = /\boverride\s+int\s+GetHashCode\s*\(\s*\)/;

  // Python: __eq__ without __hash__ or vice versa
  const HAS_EQ_PYTHON = /\bdef\s+__eq__\s*\(\s*self/;
  const HAS_HASH_PYTHON = /\bdef\s+__hash__\s*\(\s*self/;

  // Kotlin: equals without hashCode
  const HAS_EQUALS_KOTLIN = /\boverride\s+fun\s+equals\s*\(/;
  const HAS_HASHCODE_KOTLIN = /\boverride\s+fun\s+hashCode\s*\(\s*\)/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub)\b/i.test(node.label)) continue;

    let hasEquals = false;
    let hasHashCode = false;
    let lang = '';

    if (HAS_EQUALS_JAVA.test(code) || HAS_HASHCODE_JAVA.test(code)) {
      hasEquals = HAS_EQUALS_JAVA.test(code);
      hasHashCode = HAS_HASHCODE_JAVA.test(code);
      lang = 'Java';
    } else if (HAS_EQUALS_CSHARP.test(code) || HAS_GETHASHCODE_CSHARP.test(code)) {
      hasEquals = HAS_EQUALS_CSHARP.test(code);
      hasHashCode = HAS_GETHASHCODE_CSHARP.test(code);
      lang = 'C#';
    } else if (HAS_EQ_PYTHON.test(code) || HAS_HASH_PYTHON.test(code)) {
      hasEquals = HAS_EQ_PYTHON.test(code);
      hasHashCode = HAS_HASH_PYTHON.test(code);
      lang = 'Python';
    } else if (HAS_EQUALS_KOTLIN.test(code) || HAS_HASHCODE_KOTLIN.test(code)) {
      hasEquals = HAS_EQUALS_KOTLIN.test(code);
      hasHashCode = HAS_HASHCODE_KOTLIN.test(code);
      lang = 'Kotlin';
    }

    if (hasEquals && !hasHashCode) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'STRUCTURAL (hashCode/GetHashCode/__hash__ override)',
        severity: 'medium',
        description: `${node.label} overrides equals() but not hashCode() (${lang}). Objects that are ` +
          `"equal" can hash to different buckets, breaking HashMap/HashSet contracts. In auth contexts, ` +
          `this can cause session lookup failures or authorization bypass.`,
        fix: `Override hashCode() consistently with equals(). In ${lang}, ensure that ` +
          `a.equals(b) implies a.hashCode() == b.hashCode(). Use Objects.hash() (Java), ` +
          `HashCode.Combine() (C#), or tuple hashing (Python).`,
      });
    } else if (!hasEquals && hasHashCode) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'STRUCTURAL (equals/Equals/__eq__ override)',
        severity: 'medium',
        description: `${node.label} overrides hashCode() but not equals() (${lang}). Two objects with ` +
          `the same hash may not compare equal, causing phantom duplicates in hash-based collections. ` +
          `Identity checks become inconsistent.`,
        fix: `Override equals() consistently with hashCode(). The contract requires that ` +
          `equal objects have equal hash codes, but also that the equality check is meaningful.`,
      });
    }
  }

  return { cwe: 'CWE-581', name: 'Object Model Violation: Just One of Equals and Hashcode Defined', holds: findings.length === 0, findings };
}

/**
 * CWE-584: Return Inside Finally Block
 * A return statement in a finally block silently swallows any exception from
 * the try block and overrides any return value from try/catch. This hides
 * security-critical errors (failed auth, failed validation) and makes the
 * function appear to succeed when it should have failed.
 */
function verifyCWE584(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Java/C#/JS/TS: return inside finally
  const FINALLY_RETURN = /\bfinally\s*\{[^}]*\breturn\b/;
  // More thorough: multi-line finally with return
  const FINALLY_BLOCK_RETURN = /\bfinally\s*\{[\s\S]{0,500}?\breturn\s/;
  // Python: return inside finally
  const PYTHON_FINALLY_RETURN = /\bfinally\s*:[\s\S]{0,300}?\breturn\s/;

  // Safe: return in a nested function/lambda inside finally (not the finally's return)
  const NESTED_FN = /\bfinally\s*\{[\s\S]*?(?:function\s*\(|=>\s*\{|lambda\s)[\s\S]*?\breturn\b/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub)\b/i.test(node.label)) continue;

    const hasReturn = FINALLY_RETURN.test(code) || FINALLY_BLOCK_RETURN.test(code) || PYTHON_FINALLY_RETURN.test(code);
    const isNested = NESTED_FN.test(code);

    if (hasReturn && !isNested) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'STRUCTURAL (no return/throw in finally blocks)',
        severity: 'high',
        description: `${node.label} has a return statement inside a finally block. This silently ` +
          `swallows any exception thrown in the try/catch block and overrides the try block's return ` +
          `value. If the try block throws a security exception (auth failure, validation error), ` +
          `the finally return hides it — the caller sees success.`,
        fix: 'Remove the return from the finally block. Use a variable to store the return value ' +
          'in try/catch, then return it after the finally block. The finally block should only ' +
          'perform cleanup (close resources, release locks).',
      });
    }
  }

  return { cwe: 'CWE-584', name: 'Return Inside Finally Block', holds: findings.length === 0, findings };
}

/**
 * CWE-588: Attempt to Access Child of a Non-existent Index Entry
 * Accessing a nested property/index without checking the parent exists.
 * Classic pattern: array[i].field without bounds check, or map.get(key).method()
 * without null check. This causes null pointer dereferences or undefined behavior
 * that can crash services (DoS) or skip security checks.
 */
function verifyCWE588(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const mapLang = inferMapLanguage(map);

  // Library code accesses deeply nested properties on known internal structures — not external data
  if (isLibraryCode(map)) {
    return { cwe: 'CWE-588', name: 'Attempt to Access Child of Non-existent Index Entry', holds: true, findings };
  }

  // C/C++: array[expr].member without bounds check
  const C_NESTED_ACCESS = /\w+\s*\[[^\]]+\]\s*\.\s*\w+/;
  const C_BOUNDS_CHECK = /\bif\s*\([^)]*(?:>=?\s*0|<\s*\w+|!=\s*NULL|!=\s*nullptr)\b/;

  // Java: .get(key).method() without null check
  const JAVA_CHAINED_GET = /\.get\s*\([^)]*\)\s*\.\s*\w+/;
  const JAVA_NULL_CHECK = /\bif\s*\([^)]*!=\s*null\b|Optional\.|\.orElse\(|\.ifPresent\(/;

  // JS/TS: deeply nested property access without optional chaining or guard
  const JS_DEEP_ACCESS = /\w+(?:\[[^\]]+\]|\.\w+){3,}/;
  const JS_OPTIONAL_CHAIN = /\?\./;
  const JS_GUARD = /\bif\s*\([^)]*(?:!=\s*(?:null|undefined)|typeof\s+\w+\s*!==?\s*['"]undefined['"])\b/;

  // Python: dict[key][nested] without .get() or try/except
  const PY_NESTED_DICT = /\w+\[[^\]]+\]\s*\[[^\]]+\]/;
  const PY_SAFE = /\.get\s*\(|try\s*:|KeyError|IndexError/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub)\b/i.test(node.label)) continue;

    let matched = false;
    let detail = '';

    if (C_NESTED_ACCESS.test(code) && !C_BOUNDS_CHECK.test(code) &&
        /\b(?:int|char|struct|float|double|void)\b/.test(code)) {
      matched = true;
      detail = 'accesses member of array element without bounds checking the index';
    } else if (JAVA_CHAINED_GET.test(code) && !JAVA_NULL_CHECK.test(code) &&
               /\b(?:Map|HashMap|List|ArrayList|get)\b/.test(code)) {
      matched = true;
      detail = 'chains method call on .get() result without null check — NPE if key missing';
    } else if (JS_DEEP_ACCESS.test(code) && !JS_OPTIONAL_CHAIN.test(code) && !JS_GUARD.test(code) &&
               /\b(?:req\.|params|query|body|config|data|response|result)\b/.test(code) &&
               // Only flag for JS/TS/Python — Java method chaining is normal, not a CWE-588 pattern
               (['javascript', 'typescript', 'python', ''].some(l => mapLang === l))) {
      matched = true;
      detail = 'deeply nested property access on external data without optional chaining or null guard';
    } else if (PY_NESTED_DICT.test(code) && !PY_SAFE.test(code)) {
      matched = true;
      detail = 'nested dict/list indexing without .get() or try/except — KeyError/IndexError if missing';
    }

    if (matched) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (existence check before nested access)',
        severity: 'medium',
        description: `${node.label} ${detail}. If the parent entry does not exist, ` +
          `this causes a null dereference, TypeError, or undefined behavior. In request handlers, ` +
          `this is a crash vector (DoS). In auth paths, it can skip security checks entirely.`,
        fix: 'Check parent existence before accessing children. Use optional chaining (?.) in JS/TS, ' +
          'Optional.map() in Java, .get() with default in Python, or explicit bounds/null checks in C.',
      });
    }
  }

  return { cwe: 'CWE-588', name: 'Attempt to Access Child of Non-existent Index Entry', holds: findings.length === 0, findings };
}

/**
 * CWE-589: Call to Non-ubiquitous API
 * Using platform-specific APIs that are not available across all deployment
 * targets. This causes runtime failures in production when code runs on a
 * different OS/platform than development. Security impact: features that
 * "work in dev" silently fail in production, including security controls.
 */
function verifyCWE589(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Windows-only APIs used in presumably cross-platform code
  const WIN_ONLY_API = /\b(?:GetWindowsDirectory|RegOpenKey|RegQueryValue|CreateFile[AW]|WinExec|ShellExecute[AW]|MessageBox[AW]|FindFirstFile[AW]|GetModuleHandle|LoadLibrary[AW]|HKEY_\w+|HANDLE\s+\w+\s*=\s*CreateFile)\b/;

  // Unix-only APIs that fail on Windows
  const UNIX_ONLY_API = /\b(?:fork\s*\(|execvp?\s*\(|setuid\s*\(|setgid\s*\(|chroot\s*\(|syslog\s*\(|getpwnam\s*\(|getgrnam\s*\(|fchmod\s*\(|mmap\s*\((?!.*MAP_ANON))\b/;

  // Deprecated/removed APIs across versions
  const DEPRECATED_API = /\b(?:gets\s*\(|sprintf\s*\((?!.*snprintf)|tmpnam\s*\(|mktemp\s*\(|asctime\s*\(|ctime\s*\(|rand\s*\()\b/;

  // Python: platform-specific modules
  const PY_PLATFORM = /\b(?:import\s+(?:winreg|_winapi|msvcrt|posix|fcntl|termios|grp|pwd))\b/;

  // Node.js: Windows vs Unix differences
  const NODE_PLATFORM = /\b(?:child_process\.exec(?:Sync)?\s*\([^)]*(?:cmd\.exe|powershell|\/bin\/sh))\b/;

  // Safe: platform checks guard the call
  const PLATFORM_GUARD = /\b(?:process\.platform|os\.platform|sys\.platform|os\.name|RuntimeInformation|Platform\.OS|navigator\.platform|Environment\.OSVersion)\b/;
  const IFDEF_GUARD = /\b(?:#ifdef\s+(?:_WIN32|__linux__|__APPLE__)|#if\s+defined\s*\((?:_WIN32|__linux__))\b/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub)\b/i.test(node.label)) continue;

    const hasPlatformGuard = PLATFORM_GUARD.test(code) || IFDEF_GUARD.test(code);
    if (hasPlatformGuard) continue;

    let matched = false;
    let detail = '';

    if (WIN_ONLY_API.test(code)) {
      matched = true;
      detail = 'uses Windows-only API without platform guard — fails on Linux/macOS deployments';
    } else if (UNIX_ONLY_API.test(code) && !/\b_WIN32\b/.test(code)) {
      matched = true;
      detail = 'uses Unix-only API without platform guard — fails on Windows deployments';
    } else if (DEPRECATED_API.test(code) && !/(snprintf|fgets|mkstemp|tmpfile)/.test(code)) {
      matched = true;
      detail = 'uses deprecated/removed C API that may not exist on all platforms or compiler versions';
    } else if (PY_PLATFORM.test(code)) {
      matched = true;
      detail = 'imports platform-specific Python module without platform check';
    } else if (NODE_PLATFORM.test(code)) {
      matched = true;
      detail = 'hardcodes platform-specific shell path in child_process call';
    }

    if (matched) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (platform detection guard before platform-specific API)',
        severity: 'low',
        description: `${node.label} ${detail}. Code that works in development may fail silently ` +
          `or crash in production on a different platform. If security controls depend on this code, ` +
          `they are silently disabled on unsupported platforms.`,
        fix: 'Guard platform-specific calls with runtime platform detection (process.platform, ' +
          'sys.platform, #ifdef _WIN32, etc.) or use cross-platform abstractions.',
      });
    }
  }

  return { cwe: 'CWE-589', name: 'Call to Non-ubiquitous API', holds: findings.length === 0, findings };
}

/**
 * CWE-590: Free of Memory not on the Heap
 * Calling free()/delete on stack-allocated memory, global/static memory, or
 * already-freed memory. This corrupts the heap allocator metadata and leads
 * to arbitrary code execution via heap exploitation.
 */
function verifyCWE590(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // free() or delete on address-of local variable: free(&localVar)
  const FREE_ADDR_OF = /\bfree\s*\(\s*&\s*\w+\s*\)/;
  // delete on stack variable
  const DELETE_STACK = /\bdelete\s+(?:&\s*)?\w+\s*;/;

  // free() on a string literal or static buffer
  const FREE_LITERAL = /\bfree\s*\(\s*(?:"[^"]*"|'[^']*')\s*\)/;

  // free() inside a function where the variable was declared as local array
  const LOCAL_ARRAY_FREE = /\b(?:char|int|float|double|unsigned|long|short)\s+(\w+)\s*\[[\w\s]*\]\s*;[\s\S]{0,500}?\bfree\s*\(\s*\1\s*\)/;

  // free() on a static variable
  const STATIC_FREE = /\bstatic\s+\w+\s*\*?\s*(\w+)[\s\S]{0,500}?\bfree\s*\(\s*\1\s*\)/;

  // Safe: variable was obtained from malloc/calloc/realloc/strdup
  const HEAP_ALLOC = /\b(?:malloc|calloc|realloc|strdup|strndup|new\s+\w+|new\s*\[)\b/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub)\b/i.test(node.label)) continue;

    let matched = false;
    let detail = '';

    if (FREE_ADDR_OF.test(code)) {
      matched = true;
      detail = 'calls free() on address of a local (stack) variable';
    } else if (FREE_LITERAL.test(code)) {
      matched = true;
      detail = 'calls free() on a string literal (read-only data segment)';
    } else if (LOCAL_ARRAY_FREE.test(code)) {
      matched = true;
      detail = 'calls free() on a stack-allocated array';
    } else if (STATIC_FREE.test(code) && !HEAP_ALLOC.test(code)) {
      matched = true;
      detail = 'calls free() on a static variable (not heap-allocated)';
    }

    if (matched) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'STRUCTURAL (only free heap-allocated memory)',
        severity: 'critical',
        description: `${node.label} ${detail}. Freeing non-heap memory corrupts the heap allocator's ` +
          `internal metadata. An attacker can exploit this to achieve arbitrary write (heap ` +
          `corruption → controlled allocation → code execution).`,
        fix: 'Only call free()/delete on pointers returned by malloc()/calloc()/realloc()/new. ' +
          'Never free stack variables, string literals, or static data. ' +
          'Use AddressSanitizer (-fsanitize=address) to detect at runtime.',
      });
    }
  }

  return { cwe: 'CWE-590', name: 'Free of Memory not on the Heap', holds: findings.length === 0, findings };
}

/**
 * CWE-591: Sensitive Data Storage in Improperly Locked Memory
 * Sensitive data (keys, passwords, tokens) stored in memory that can be
 * swapped to disk. When memory pages are swapped out, secrets end up in
 * the swap file/partition where they persist after the process exits.
 * Proper handling: mlock()/VirtualLock() to pin pages, or secure memory
 * allocators like sodium_malloc().
 */
function verifyCWE591(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Patterns indicating sensitive data in memory
  const SENSITIVE_VAR = /\b(?:password|secret|private[_]?key|priv[_]?key|master[_]?key|encryption[_]?key|api[_]?key|token|credential|passphrase|signing[_]?key|session[_]?key)\b/i;

  // C/C++: sensitive buffer without mlock
  const C_BUFFER = /\b(?:char|unsigned\s+char|uint8_t|BYTE)\s+\*?\s*\w*(?:password|secret|key|token|cred)\w*\s*(?:\[[\w\s]*\]|\s*=\s*(?:malloc|calloc|new))/i;

  // Safe: memory locking APIs
  const MLOCK_SAFE = /\b(?:mlock|mlockall|VirtualLock|sodium_malloc|sodium_mlock|SecureString|OPENSSL_secure_malloc|OPENSSL_cleanse|SecureZeroMemory|explicit_bzero|memset_s)\b/;

  // Safe: secure memory wrappers
  const SECURE_WRAPPER = /\b(?:SecureString|ProtectedData|CryptProtectMemory|SecureBuffer|sodium_memzero|OPENSSL_secure_free)\b/;

  // Rust: sensitive data without zeroize
  const RUST_SENSITIVE = /\b(?:let\s+(?:mut\s+)?(?:password|secret|key|token)\s*(?::\s*(?:Vec<u8>|String|\[u8))?)/;
  const RUST_SAFE = /\b(?:zeroize|secrecy::Secret|Zeroizing)\b/;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (/\b(test|spec|mock|stub|example|demo)\b/i.test(node.label)) continue;

    const hasSensitiveData = SENSITIVE_VAR.test(code);
    if (!hasSensitiveData) continue;

    const hasMemoryLock = MLOCK_SAFE.test(code) || SECURE_WRAPPER.test(code) || RUST_SAFE.test(code);
    if (hasMemoryLock) continue;

    let matched = false;
    let detail = '';

    if (C_BUFFER.test(code)) {
      matched = true;
      detail = 'stores sensitive data in unlocked memory buffer — can be swapped to disk';
    } else if (RUST_SENSITIVE.test(code) && !RUST_SAFE.test(code)) {
      matched = true;
      detail = 'stores sensitive data without zeroize/secrecy — remains in memory after drop';
    } else if (/\b(?:private_key|secret_key|password|master_key)\s*=\s*(?:new\s+(?:byte|char)|Buffer\.(?:from|alloc))/i.test(code)) {
      matched = true;
      detail = 'stores cryptographic material in standard (swappable) memory';
    }

    if (matched) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (memory locking for sensitive data)',
        severity: 'high',
        description: `${node.label} ${detail}. The OS can swap these memory pages to disk, where ` +
          `secrets persist in the swap file after the process exits. Core dumps also capture ` +
          `unlocked pages. An attacker with disk access recovers secrets from swap/core.`,
        fix: 'Use mlock()/VirtualLock() to pin sensitive pages in RAM. Use sodium_malloc() for ' +
          'guard-paged, locked allocations. In Rust, use secrecy::Secret<T> with Zeroize. ' +
          'In .NET, use SecureString. Always zero memory before freeing (explicit_bzero, ' +
          'SecureZeroMemory, sodium_memzero).',
      });
    }
  }

  return { cwe: 'CWE-591', name: 'Sensitive Data Storage in Improperly Locked Memory', holds: findings.length === 0, findings };
}

/**
 * CWE-605: Multiple Binds to the Same Port
 * Pattern: Server code that binds/listens on a port without checking if it's already
 * in use, or multiple listen() calls on the same port. This can cause race conditions,
 * service denial, or port hijacking where an attacker binds first.
 */
function verifyCWE605(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Library code defines server/listen primitives — not actually binding ports
  if (isLibraryCode(map)) {
    return { cwe: 'CWE-605', name: 'Multiple Binds to Same Port', holds: true, findings };
  }

  const LISTEN_RE = /\b(\.listen\s*\(|\.bind\s*\(|createServer|net\.createServer|http\.createServer|https\.createServer|express\(\)|app\.listen|server\.listen|socket\.bind|dgram\.createSocket|new\s+Server|ServerSocket|socket\.listen|SOCK_STREAM|SO_REUSEADDR|SO_REUSEPORT|bind\s*\(\s*['"]?(?:0\.0\.0\.0|localhost|127\.0\.0\.1|::))\b/i;
  const PORT_RE = /\b(?:port|PORT|listen)\s*[:=(\s]\s*(\d{2,5})\b/;
  const SAFE_RE = /\b(SO_EXCLUSIVEADDRUSE|exclusive\s*:\s*true|address\s*already\s*in\s*use|EADDRINUSE|port.?in.?use|isPortAvailable|checkPort|portfinder|detect-port|get-port|getPort|find.?free.?port|freeport|cluster\.fork|cluster\.isMaster|cluster\.isPrimary|process\.env\.PORT|\.on\s*\(\s*['"]error['"])\b/i;

  // Collect all nodes that listen/bind on ports
  const listenNodes: Array<{ node: NeuralMapNode; port: string }> = [];
  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (LISTEN_RE.test(code)) {
      const portMatch = PORT_RE.exec(code);
      const port = portMatch ? portMatch[1] : 'unknown';
      listenNodes.push({ node, port });
    }
  }

  // Check 1: Multiple binds to the same port
  const portMap = new Map<string, NeuralMapNode[]>();
  for (const { node, port } of listenNodes) {
    if (port !== 'unknown') {
      const arr = portMap.get(port) ?? [];
      arr.push(node);
      portMap.set(port, arr);
    }
  }
  for (const [port, nodes] of portMap) {
    if (nodes.length > 1) {
      findings.push({
        source: nodeRef(nodes[0]),
        sink: nodeRef(nodes[1]),
        missing: 'CONTROL (single bind per port — avoid duplicate listeners)',
        severity: 'medium',
        description: `Multiple bind/listen calls on port ${port}: ${nodes[0].label} and ${nodes[1].label}. ` +
          'Duplicate port binds cause EADDRINUSE errors or race conditions where an attacker can bind first.',
        fix: 'Ensure only one process/server binds to each port. Use cluster module for multi-process, or use SO_EXCLUSIVEADDRUSE to prevent port hijacking.',
      });
    }
  }

  // Check 2: Listen without error handling for EADDRINUSE
  for (const { node } of listenNodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (!SAFE_RE.test(code)) {
      // Check if there's an error handler nearby in the same scope
      const nearbyNodes = map.nodes.filter(n =>
        Math.abs(n.line_start - node.line_start) < 15 &&
        SAFE_RE.test(stripComments(n.analysis_snapshot || n.code_snapshot))
      );
      if (nearbyNodes.length === 0) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (port-in-use error handling)',
          severity: 'low',
          description: `Server at ${node.label} binds to a port without checking availability or handling EADDRINUSE. ` +
            'An attacker could bind to the port first, intercepting traffic (port hijacking).',
          fix: 'Handle EADDRINUSE errors. Use exclusive address binding (SO_EXCLUSIVEADDRUSE on Windows, ' +
            'exclusive: true in Node.js). Check port availability before binding.',
        });
      }
    }
  }

  return { cwe: 'CWE-605', name: 'Multiple Binds to the Same Port', holds: findings.length === 0, findings };
}

/* REMOVED: verifyCWE612 — now in sensitive-data.ts */

/**
 * CWE-613: Insufficient Session Expiration
 * Pattern: Sessions that don't expire or have excessively long timeouts, allowing
 * stolen session tokens to be used indefinitely. Checks for missing maxAge/expires,
 * excessively long session durations, and missing idle timeout.
 */
function verifyCWE613(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Session configuration patterns
  const SESSION_CONFIG_RE = /\b(session\s*\(|express.?session|cookie.?session|SessionMiddleware|SESSION_ENGINE|session\.configure|createSession|sessionOptions|session.?config|session.?store|SessionStore|connect-redis|connect-mongo|express-mysql-session|memoryStore|fileStore)\b/i;
  // Expiration configuration
  const EXPIRY_RE = /\b(maxAge|max.?age|expires|expiration|ttl|timeout|lifetime|max.?inactive|idle.?timeout|absolute.?timeout|session.?duration|cookie.*(?:maxAge|expires)|SESSION_COOKIE_AGE|SESSION_TIMEOUT|SESSION_LIFETIME|session.?expiry|inactivity.?timeout)\b/i;
  // Excessively long session durations (> 24 hours in various units)
  const LONG_DURATION_MS_RE = /(?:maxAge|max.?age|expires|ttl|timeout|lifetime)\s*[:=]\s*(\d+)/i;
  // Safe patterns
  const SAFE_RE = /\b(rolling\s*:\s*true|resave|touch|session\.touch|session\.regenerate|session\.destroy|absolute.?timeout|idle.?timeout|sliding.?expiration|session.?cleanup|session.?gc|pruneSession|clearExpired|SESSION_COOKIE_AGE\s*[:=]\s*\d{1,5}\b|maxAge\s*[:=]\s*\d{1,7}\b)\b/i;
  // Logout/invalidation patterns
  const LOGOUT_RE = /\b(logout|log.?out|sign.?out|session\.destroy|session\.invalidate|req\.logout|endSession|clearSession|revokeSession|removeSession|deleteSession)\b/i;

  // Check 0: Java setMaxInactiveInterval with negative or zero value (session never expires)
  const JAVA_SESSION_NEVER_EXPIRE = /\bsetMaxInactiveInterval\s*\(\s*(-\d+|0)\s*\)/;
  const JAVA_SESSION_CONFIGURE = /\bsetMaxInactiveInterval\s*\(/;
  for (const node of map.nodes) {
    const code = node.analysis_snapshot || node.code_snapshot;
    if (JAVA_SESSION_NEVER_EXPIRE.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (session expiration — setMaxInactiveInterval must be positive)',
        severity: 'high',
        description: `Session at ${node.label} configured with negative/zero timeout via setMaxInactiveInterval(). ` +
          `A negative value means the session never expires, and zero means immediate expiration. ` +
          `Never-expiring sessions allow stolen session tokens to be reused indefinitely.`,
        fix: 'Set a reasonable positive timeout: session.setMaxInactiveInterval(1800) for 30 minutes. ' +
          'Enforce both idle timeout and absolute timeout. Invalidate sessions on logout.',
      });
    }
  }

  // Check 0b: Java getSession() without setMaxInactiveInterval — no timeout configured
  const allCode613 = map.nodes.map(n => n.analysis_snapshot || n.code_snapshot).join('\n');
  if (/\bgetSession\s*\(/.test(allCode613) && !JAVA_SESSION_CONFIGURE.test(allCode613) && /\bjavax\.servlet|jakarta\.servlet/.test(allCode613)) {
    // Only flag if there's evidence of session usage without ANY timeout config
    const sessionNode = map.nodes.find(n => /\bgetSession\s*\(/.test(n.analysis_snapshot || n.code_snapshot));
    if (sessionNode && !SESSION_CONFIG_RE.test(allCode613) && !EXPIRY_RE.test(allCode613)) {
      // Don't flag — the web.xml may configure it. Only flag explicit bad values above.
    }
  }

  // Check 1: Session configuration without expiration
  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (SESSION_CONFIG_RE.test(code)) {
      if (!EXPIRY_RE.test(code)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (session expiration configuration — maxAge or expires)',
          severity: 'high',
          description: `Session configuration at ${node.label} does not set an expiration time. ` +
            'Sessions without expiration remain valid indefinitely, allowing stolen tokens to be reused without limit.',
          fix: 'Set session maxAge/expires. Use both absolute timeout (max session lifetime) and idle timeout ' +
            '(inactivity limit). Recommended: 15-30 min idle, 8-24h absolute for web apps.',
        });
      } else {
        // Check for excessively long durations
        const durationMatch = LONG_DURATION_MS_RE.exec(code);
        if (durationMatch) {
          const value = parseInt(durationMatch[1], 10);
          // If raw number > 86400000 (24h in ms) it's likely milliseconds and too long
          // If raw number > 86400 and code doesn't show * 1000, likely seconds and too long
          const isMs = /\*\s*1000/.test(code) || value > 100000;
          const durationMs = isMs ? value : value * 1000;
          const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
          if (durationMs > SEVEN_DAYS_MS) {
            findings.push({
              source: nodeRef(node),
              sink: nodeRef(node),
              missing: 'CONTROL (reasonable session timeout — current is > 7 days)',
              severity: 'medium',
              description: `Session at ${node.label} has an excessively long timeout (${Math.round(durationMs / 86400000)} days). ` +
                'Long-lived sessions increase the window for session hijacking.',
              fix: 'Reduce session timeout. For web applications: 15-30 min idle timeout, 8-24h absolute timeout. ' +
                'For APIs: use short-lived access tokens (15-60 min) with refresh tokens.',
            });
          }
        }
      }
    }
  }

  // Check 2: JWT/token without expiration
  const JWT_RE = /\b(jwt\.sign|jsonwebtoken|jose\.|nimbus|JWT\.create|JWTCreator|createToken|generateToken|signToken|issueToken)\b/i;
  const JWT_EXPIRY_RE = /\b(expiresIn|exp|expiration|maxAge|ttl|iat.*exp|nbf|setExpiration|withExpiresAt|\.setIssuedAt|setTTL|tokenLifetime|token.?expiry)\b/i;
  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (JWT_RE.test(code) && !JWT_EXPIRY_RE.test(code)) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (JWT/token expiration — expiresIn or exp claim)',
        severity: 'high',
        description: `Token creation at ${node.label} does not set an expiration (exp claim). ` +
          'Tokens without expiration are valid forever and cannot be effectively revoked.',
        fix: 'Always set expiresIn/exp when creating JWTs. Use short-lived access tokens (15-60 min) ' +
          'with a refresh token rotation strategy. Validate exp on every request.',
      });
    }
  }

  // Check 3: No logout/session-destroy endpoint
  const hasAuth = map.nodes.some(n =>
    n.node_type === 'AUTH' || /\b(login|authenticate|sign.?in)\b/i.test(n.analysis_snapshot || n.code_snapshot)
  );
  const hasLogout = map.nodes.some(n => LOGOUT_RE.test(stripComments(n.analysis_snapshot || n.code_snapshot)));
  if (hasAuth && !hasLogout) {
    const authNode = map.nodes.find(n =>
      n.node_type === 'AUTH' || /\b(login|authenticate|sign.?in)\b/i.test(n.analysis_snapshot || n.code_snapshot)
    );
    if (authNode) {
      findings.push({
        source: nodeRef(authNode),
        sink: nodeRef(authNode),
        missing: 'CONTROL (session invalidation / logout endpoint)',
        severity: 'medium',
        description: `Application has authentication at ${authNode.label} but no session destruction/logout mechanism. ` +
          'Users cannot explicitly end sessions, leaving tokens valid until natural expiration.',
        fix: 'Implement a logout endpoint that destroys the server-side session (req.session.destroy()) ' +
          'and clears the session cookie. For JWTs, maintain a token blocklist or use short-lived tokens with refresh token revocation.',
      });
    }
  }

  return { cwe: 'CWE-613', name: 'Insufficient Session Expiration', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-616: Incomplete Identification of Uploaded File Variables (PHP)
//
// In PHP, file uploads populate $_FILES with multiple properties (name, type,
// tmp_name, error, size). If code only checks $_FILES['x']['name'] or
// $_FILES['x']['type'] (client-controlled) without checking 'error' or
// using 'tmp_name' with move_uploaded_file(), attackers can bypass upload
// validation or overwrite arbitrary files.
// ---------------------------------------------------------------------------

function verifyCWE616(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const FILES_ACCESS = /\$_FILES\s*\[/i;
  const UPLOAD_VAR = /\b(req\.files?\b|request\.files?\b|\$_FILES|upload.*\bname\b|file.*\bname\b|multipart.*filename|original_?name|getClientOriginalName|getClientMimeType)\b/i;
  const CLIENT_ONLY_CHECK = /\$_FILES\s*\[\s*['"][^'"]+['"]\s*\]\s*\[\s*['"](?:name|type)['"]\s*\]/i;
  const SAFE_UPLOAD = /\b(move_uploaded_file|is_uploaded_file|tmp_name|getPathname|getRealPath|getClientOriginalExtension.*(?:allowedExtensions|whitelist|allowlist)|UPLOAD_ERR_OK|\['error'\]|finfo_file|finfo_open|mime_content_type|getimagesize|exif_imagetype|fileinfo|getMimeType|getSize|hashName|store\(|storeAs\()\b/i;
  const ERROR_CHECK = /\$_FILES\s*\[\s*['"][^'"]+['"]\s*\]\s*\[\s*['"]error['"]\s*\]/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);

    if (FILES_ACCESS.test(code)) {
      if (CLIENT_ONLY_CHECK.test(code) && !SAFE_UPLOAD.test(code) && !ERROR_CHECK.test(code)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (check $_FILES error code and use move_uploaded_file with tmp_name)',
          severity: 'high',
          description: `${node.label} accesses $_FILES name/type (client-controlled) without checking ` +
            `the error field or using move_uploaded_file(). The client can set any filename and MIME type. ` +
            `Without checking $_FILES['x']['error'] === UPLOAD_ERR_OK and using tmp_name, the upload ` +
            `handling may process non-uploaded files or miss upload failures.`,
          fix: 'Always check $_FILES["x"]["error"] === UPLOAD_ERR_OK first. Use move_uploaded_file($_FILES["x"]["tmp_name"], $dest) ' +
            'which verifies the file was actually uploaded via HTTP POST. Never trust $_FILES["x"]["name"] or ["type"] — ' +
            'validate extensions against an allowlist and check MIME with finfo_file().',
        });
        continue;
      }
    }

    if (node.node_type === 'INGRESS' || node.node_type === 'TRANSFORM') {
      if (UPLOAD_VAR.test(code) && !SAFE_UPLOAD.test(code)) {
        const usesClientName = /\b(original_?name|getClientOriginalName|getClientMimeType|\['name'\]|\["name"\]|\.name\b|filename)\b/i.test(code);
        const hasFileWrite = /\b(rename|copy|move|fwrite|file_put_contents|writeFile|saveTo|pipe|createWriteStream)\b/i.test(code);

        if (usesClientName && hasFileWrite) {
          findings.push({
            source: nodeRef(node), sink: nodeRef(node),
            missing: 'CONTROL (validate upload variables server-side — do not trust client filename/MIME)',
            severity: 'high',
            description: `${node.label} uses the client-supplied filename directly in a file write operation. ` +
              `The client controls the filename and can set it to path traversal sequences (../../etc/passwd) ` +
              `or dangerous extensions (.php, .jsp). All upload variables from the client are attacker-controlled.`,
            fix: 'Generate a safe filename server-side (e.g., UUID + validated extension). ' +
              'Validate the extension against an allowlist. Check the file content with finfo/magic bytes. ' +
              'Never use the client filename directly in file system operations.',
          });
        }
      }
    }
  }

  const ingress = nodesOfType(map, 'INGRESS');
  const uploadIngress = ingress.filter(n =>
    /\b(upload|file|multipart|\$_FILES)\b/i.test(n.analysis_snapshot || n.code_snapshot) ||
    n.node_subtype.includes('upload') || n.node_subtype.includes('file') ||
    n.attack_surface.includes('file_upload')
  );

  const fileSinks = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    /\b(rename|move|copy|writeFile|fwrite|file_put_contents|save|mv\(|move_uploaded_file)\b/i.test(n.analysis_snapshot || n.code_snapshot)
  );

  for (const src of uploadIngress) {
    for (const sink of fileSinks) {
      if (src.id === sink.id) continue;
      if (findings.some(f => f.sink.id === sink.id && f.source.id === src.id)) continue;
      const sinkCode = stripComments(sink.analysis_snapshot || sink.code_snapshot);
      if (SAFE_UPLOAD.test(sinkCode)) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        findings.push({
          source: nodeRef(src), sink: nodeRef(sink),
          missing: 'CONTROL (validate all upload file variables before file operation)',
          severity: 'high',
          description: `Upload data from ${src.label} flows to file operation at ${sink.label} without ` +
            `complete validation of upload variables. PHP $_FILES contains 5 variables per upload ` +
            `(name, type, tmp_name, error, size) — all must be checked for safe handling.`,
          fix: 'Check error code, validate file size, verify MIME type server-side (finfo_file), ' +
            'generate a safe destination filename, and use move_uploaded_file() for the actual move.',
        });
      }
    }
  }

  return { cwe: 'CWE-616', name: 'Incomplete Identification of Uploaded File Variables (PHP)', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-621: Variable Extraction Error
//
// Using functions like PHP's extract(), Ruby's binding.eval, or dynamic
// variable creation from user input that overwrites existing variables.
// extract($_GET) or extract($_POST) lets attackers overwrite any local variable
// including authentication flags, configuration, and control flow variables.
// ---------------------------------------------------------------------------

function verifyCWE621(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  const EXTRACT_SUPERGLOBAL = /\bextract\s*\(\s*\$_(GET|POST|REQUEST|COOKIE|SERVER|FILES|ENV)\b/i;
  const EXTRACT_GENERIC = /\b(extract\s*\(|parse_str\s*\(\s*[^,)]+\s*\)|import_request_variables|mb_parse_str\s*\(\s*[^,)]+\s*\))/i;
  const VAR_VARS = /\$\$\w+\s*=/;
  const PY_EXTRACT = /\b(locals\(\)\s*\.?\s*update|globals\(\)\s*\.?\s*update|exec\s*\(|vars\(\)\s*\[|setattr\s*\(\s*(?:self|cls|module))/i;
  const RUBY_EXTRACT = /\b(binding\.eval|instance_variable_set|define_method|class_eval|module_eval|send\s*\(\s*(?:params|request))/i;
  const JS_EXTRACT = /\b(Object\.assign\s*\(\s*(?:this|global|window|globalThis|self)\s*,|with\s*\(|eval\s*\(.*(?:req\.|params\.|query\.|body\.))/i;
  const SAFE_EXTRACT = /\b(EXTR_SKIP|EXTR_PREFIX|EXTR_IF_EXISTS|extract\s*\([^)]+,\s*EXTR_|parse_str\s*\([^,]+,\s*\$|mb_parse_str\s*\([^,]+,\s*\$|Object\.freeze|Object\.seal)\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);

    if (EXTRACT_SUPERGLOBAL.test(code) && !SAFE_EXTRACT.test(code)) {
      const match = code.match(EXTRACT_SUPERGLOBAL);
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (never use extract() on superglobals — use explicit variable assignment)',
        severity: 'critical',
        description: `${node.label} calls extract() on $_${match?.[1] ?? 'REQUEST'}, which imports ALL user-supplied ` +
          `parameters as local variables. An attacker can overwrite ANY variable in scope — including ` +
          `$isAdmin, $authenticated, $userId, $config, etc. This is a complete variable injection attack.`,
        fix: 'Remove extract() entirely. Access request data explicitly: $name = $_POST["name"]. ' +
          'If extract is truly needed, use EXTR_SKIP to prevent overwriting: extract($data, EXTR_SKIP). ' +
          'Better: use a framework that provides structured input access (Laravel $request->input()).',
      });
      continue;
    }

    if (EXTRACT_GENERIC.test(code) && !SAFE_EXTRACT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (use EXTR_SKIP flag or explicit variable assignment instead of extract)',
        severity: 'high',
        description: `${node.label} uses extract()/parse_str() which creates variables from array keys. ` +
          `If the array source is user-controlled (even indirectly), attackers can inject variables ` +
          `that overwrite security-critical state.`,
        fix: 'Replace extract($data) with explicit assignments. If needed, use extract($data, EXTR_SKIP) ' +
          'to prevent overwriting existing variables. For parse_str(), always provide a second argument: ' +
          'parse_str($str, $result) to capture into a named array instead of local scope.',
      });
      continue;
    }

    if (VAR_VARS.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (use associative array instead of variable variables)',
        severity: 'medium',
        description: `${node.label} uses variable variables ($$var) which dynamically create/overwrite ` +
          `variables based on another variable's value. If the variable name comes from user input, ` +
          `any local variable can be overwritten.`,
        fix: 'Replace $$key = $value with an associative array: $data[$key] = $value. ' +
          'This isolates dynamic keys into a container instead of polluting the local scope.',
      });
      continue;
    }

    if (PY_EXTRACT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (use a dictionary instead of modifying locals()/globals())',
        severity: 'high',
        description: `${node.label} dynamically modifies local/global scope (locals().update, globals().update, ` +
          `exec, or setattr). If keys come from user input, attackers can overwrite security-critical variables.`,
        fix: 'Use a dictionary to store dynamic values: data[key] = value. ' +
          'Never call locals().update() or globals().update() with user-controlled data. ' +
          'Avoid exec() — use ast.literal_eval() for safe data parsing.',
      });
      continue;
    }

    if (RUBY_EXTRACT.test(code)) {
      const hasUserInput = /\b(params|request|cookies|session)\b/i.test(code);
      if (hasUserInput) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (validate method/variable names against allowlist before dynamic dispatch)',
          severity: 'high',
          description: `${node.label} uses dynamic Ruby variable/method injection (binding.eval, instance_variable_set, ` +
            `send) with potentially user-controlled input. Attackers can invoke arbitrary methods or set ` +
            `arbitrary instance variables.`,
          fix: 'Validate method/attribute names against an explicit allowlist: ' +
            'ALLOWED = [:name, :email]; raise unless ALLOWED.include?(attr). ' +
            'Use strong_parameters in Rails to whitelist permitted attributes.',
        });
        continue;
      }
    }

    if (JS_EXTRACT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (do not spread user input into global/this scope)',
        severity: 'high',
        description: `${node.label} spreads or assigns dynamic properties into this/global scope. ` +
          `If the source object contains user-controlled keys, attackers can overwrite critical ` +
          `properties including __proto__, constructor, or application state.`,
        fix: 'Use a dedicated data object instead of assigning to this/global. ' +
          'Filter keys against an allowlist before Object.assign(). ' +
          'Never use the "with" statement — it is deprecated and creates scope injection risks.',
      });
    }
  }

  const extractNodes = map.nodes.filter(n => {
    const code = n.analysis_snapshot || (n.analysis_snapshot || n.code_snapshot);
    return (EXTRACT_GENERIC.test(code) || VAR_VARS.test(code) || PY_EXTRACT.test(code) ||
            RUBY_EXTRACT.test(code) || JS_EXTRACT.test(code)) &&
           !SAFE_EXTRACT.test(stripComments(code));
  });

  for (const src of ingress) {
    for (const ext of extractNodes) {
      if (src.id === ext.id) continue;
      if (findings.some(f => f.sink.id === ext.id)) continue;
      if (hasTaintedPathWithoutControl(map, src.id, ext.id)) {
        findings.push({
          source: nodeRef(src), sink: nodeRef(ext),
          missing: 'CONTROL (validate/filter input before variable extraction)',
          severity: 'high',
          description: `User input from ${src.label} flows to variable extraction at ${ext.label}. ` +
            `The extraction function creates variables from input keys, allowing attackers to overwrite ` +
            `any variable in scope — including authentication flags and configuration.`,
          fix: 'Remove extract/dynamic variable creation, or filter the input to only contain expected keys. ' +
            'Use explicit variable assignment instead of bulk variable injection.',
        });
      }
    }
  }

  return { cwe: 'CWE-621', name: 'Variable Extraction Error', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-626: Null Byte Interaction Error (Poison Null Byte)
//
// A null byte (\0, %00) in user input can truncate strings in C-backed APIs.
// Even in higher-level languages (PHP, Python, Java), null bytes passed to
// OS-level functions (file open, path operations) get truncated by the C runtime.
// "file.php\0.jpg" passes a .jpg extension check but opens "file.php".
// ---------------------------------------------------------------------------

function verifyCWE626(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  const PATH_OPS = /\b(open\s*\(|fopen\s*\(|file_get_contents\s*\(|include\s*\(|require\s*\(|include_once\s*\(|require_once\s*\(|readfile\s*\(|unlink\s*\(|rename\s*\(|mkdir\s*\(|rmdir\s*\(|stat\s*\(|lstat\s*\(|chmod\s*\(|chown\s*\(|realpath\s*\(|readlink\s*\(|symlink\s*\(|file_exists\s*\(|is_file\s*\(|is_dir\s*\(|pathinfo\s*\(|glob\s*\(|opendir\s*\(|readdir\s*\(|os\.path\.|os\.open|os\.remove|os\.rename|os\.mkdir|os\.stat|shutil\.|pathlib\.Path|File\.open|File\.read|File\.write|File\.delete|File\.exist|IO\.read|IO\.write|fs\.readFile|fs\.writeFile|fs\.open|fs\.unlink|fs\.stat|fs\.access|fs\.rename|fs\.mkdir)\b/i;

  const SAFE_NULL = /\b(str_replace\s*\(\s*['"]\\0|str_replace\s*\(\s*chr\s*\(\s*0\s*\)|replace\s*\(\s*['"]\x00|replace\s*\(\s*\/\\0|\.replace\s*\(\s*\/\\x00|\.replace\s*\(\s*\/\\u0000|strip_null|stripNull|removeNull|\\x00|\\u0000|\.includes\s*\(\s*'\\0'|\.includes\s*\(\s*'\\x00'|\.indexOf\s*\(\s*'\\0'|\.indexOf\s*\(\s*'\\x00'|preg_replace\s*\(\s*['"]\/\\0|preg_replace\s*\(\s*['"]\/\\x00)\b/i;

  const EXT_VALIDATION = /\b(endsWith|extname|extension|pathinfo\s*\([^)]+PATHINFO_EXTENSION|\.split\s*\(\s*['"]\.\s*['"]\s*\)\s*\.?\s*pop|substr\s*\(\s*strrpos)\b/i;
  const MODERN_SAFE = /\b(Path\.of\s*\(|Paths\.get\s*\(|Files\.\w+\s*\(|pathlib\.Path|nio\.file)/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (!PATH_OPS.test(code)) continue;
    if (SAFE_NULL.test(code)) continue;

    for (const src of ingress) {
      if (src.id === node.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, node.id)) {
        const hasExtCheck = EXT_VALIDATION.test(code);
        const isModern = MODERN_SAFE.test(code);

        if (isModern) continue;

        if (hasExtCheck) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(node),
            missing: 'CONTROL (strip null bytes before extension validation and path operations)',
            severity: 'high',
            description: `${node.label} validates file extension but does not strip null bytes. ` +
              `User input from ${src.label} could contain "file.php%00.jpg" — the extension check ` +
              `sees ".jpg" but the C runtime truncates at the null byte, opening "file.php". ` +
              `This bypasses any extension-based security check.`,
            fix: 'Strip null bytes from input BEFORE any validation: $input = str_replace(chr(0), "", $input). ' +
              'In PHP 5.3.4+, fopen() rejects null bytes — but older versions and some C extensions do not. ' +
              'Best practice: reject input containing null bytes entirely rather than stripping.',
          });
        } else {
          findings.push({
            source: nodeRef(src), sink: nodeRef(node),
            missing: 'CONTROL (reject or strip null bytes from user input before file/path operations)',
            severity: 'medium',
            description: `User input from ${src.label} reaches file operation at ${node.label} without ` +
              `null byte sanitization. A poison null byte (\\0, %00) in the path can truncate the string ` +
              `at the C level, potentially accessing unintended files.`,
            fix: 'Strip or reject null bytes in user input: input.replace(/\\0/g, "") (JS), ' +
              'str_replace(chr(0), "", $input) (PHP), input.replace("\\x00", "") (Python). ' +
              'Better: reject any input containing null bytes with a 400 error.',
          });
        }
        break;
      }
    }
  }

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (SAFE_NULL.test(code)) continue;

    const PHP_INCLUDE_INJECT = /\b(include|require|include_once|require_once)\s*\(\s*\$_(GET|POST|REQUEST|COOKIE)/i;
    if (PHP_INCLUDE_INJECT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (never use user input in include/require — use allowlist)',
        severity: 'critical',
        description: `${node.label} passes user input directly to PHP include/require. Combined with a ` +
          `poison null byte, an attacker can include arbitrary files: include($_GET["page"].".php") ` +
          `with page=../../etc/passwd%00 truncates the .php suffix and includes /etc/passwd.`,
        fix: 'Never use user input in include/require. Use an allowlist: ' +
          '$pages = ["home" => "home.php", "about" => "about.php"]; include($pages[$input] ?? "404.php"). ' +
          'This eliminates both path traversal and null byte attacks entirely.',
      });
    }
  }

  return { cwe: 'CWE-626', name: 'Null Byte Interaction Error (Poison Null Byte)', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-627: Dynamic Variable Evaluation
//
// Code uses dynamic evaluation (eval, exec, Function constructor) to process
// variable names or values from user input. Similar to CWE-621 (extract) but
// focuses on eval-based variable injection: eval("$" + userInput + " = value")
// or exec(f"{var_name} = {var_value}").
// ---------------------------------------------------------------------------

function verifyCWE627(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  const EVAL_VAR_PHP = /\beval\s*\(\s*['"]?\s*\$(?!\$)/i;
  const EVAL_VAR_CONCAT = /\beval\s*\(\s*(?:['"].*\$|.*\.\s*\$_(?:GET|POST|REQUEST|COOKIE)|.*\+\s*(?:req\.|params\.|query\.|body\.))/i;
  const EXEC_VAR_PY = /\bexec\s*\(\s*(?:f['"]|['"].*\{|.*(?:format|%)\s*\()/i;
  const DYNAMIC_VAR_EVAL = /\b(eval\s*\(|exec\s*\(|compile\s*\(|ast\.literal_eval|Function\s*\()\s*[^)]*(?:\+|concat|format|`\$\{|f['"]|\.\s*\$)/i;

  // Case-sensitive: Function() constructor vs function() keyword
  const FUNCTION_CONSTRUCTOR_CS = /\bnew\s+Function\s*\(\s*[^)]*(?:\+|concat|`\$\{)/;

  const PHP_VARVAR_INPUT = /\$\{\s*\$_(GET|POST|REQUEST|COOKIE)/i;

  const PY_ATTR_INPUT = /\b(getattr|setattr|delattr)\s*\(\s*\w+\s*,\s*(?:request\.|params\.|input\[|form\[|args\[)/i;

  const SAFE_EVAL = /\b(ast\.literal_eval|JSON\.parse|json\.loads|json_decode|yaml\.safe_load|YAML\.safe_load|safe_eval|sandboxed|sandbox|safeEval|literal_eval)\b/i;
  const ALLOWLIST_CHECK = /\b(allowed|whitelist|allowlist|permitted|valid_\w+s|VALID_\w+S|in_array\s*\(.*(?:allowed|valid)|\.includes\s*\(.*(?:allowed|valid)|hasOwnProperty|\.has\s*\()\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (SAFE_EVAL.test(code)) continue;
    if (ALLOWLIST_CHECK.test(code)) continue;

    if (EVAL_VAR_CONCAT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (never eval user input — use allowlist-based dispatch)',
        severity: 'critical',
        description: `${node.label} evaluates user input via eval(). The attacker controls what code gets ` +
          `executed, which enables arbitrary code execution. In PHP, eval("\\$$var = $val") with ` +
          `user-controlled $var allows overwriting any variable and injecting code.`,
        fix: 'Remove eval entirely. Use an explicit mapping: $handlers = ["x" => fn() => ...]; ' +
          '$handlers[$input]() ?? throw. For dynamic variable access, use an array: $data[$key] = $value.',
      });
      continue;
    }

    if (PHP_VARVAR_INPUT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (use array access instead of variable variables with user input)',
        severity: 'critical',
        description: `${node.label} creates a PHP variable variable from user input: \${$_GET[...]}. ` +
          `This lets attackers read or write ANY variable in scope by controlling the GET parameter. ` +
          `Combined with variable injection, this can bypass authentication or execute arbitrary code.`,
        fix: 'Replace variable variables with array access: $data[$_GET["key"]] instead of ${$_GET["key"]}. ' +
          'Validate the key against an allowlist of expected variable names.',
      });
      continue;
    }

    if (EXEC_VAR_PY.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (never use exec() with formatted/interpolated strings)',
        severity: 'critical',
        description: `${node.label} uses Python exec() with string formatting/interpolation. ` +
          `If any interpolated value comes from user input, the attacker can inject arbitrary ` +
          `Python code. exec(f"{var_name} = {var_value}") is equivalent to eval() for injection.`,
        fix: 'Remove exec(). Use a dictionary for dynamic variable storage: data[key] = value. ' +
          'If you need dynamic attribute access, use getattr/setattr with an allowlist of permitted attributes.',
      });
      continue;
    }

    if (PY_ATTR_INPUT.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (validate attribute name against allowlist before getattr/setattr)',
        severity: 'high',
        description: `${node.label} uses getattr/setattr with user-controlled attribute name. ` +
          `An attacker can access or modify private attributes, call arbitrary methods, or ` +
          `access __class__, __dict__, __globals__ for code execution.`,
        fix: 'Validate attribute names against an explicit allowlist: ' +
          'ALLOWED_ATTRS = {"name", "email"}; if attr not in ALLOWED_ATTRS: raise ValueError. ' +
          'Never pass user input directly to getattr/setattr.',
      });
      continue;
    }

    if (DYNAMIC_VAR_EVAL.test(code) || FUNCTION_CONSTRUCTOR_CS.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (eliminate eval/Function constructor — use safe alternatives)',
        severity: 'high',
        description: `${node.label} uses dynamic evaluation with string concatenation/interpolation. ` +
          `If any part of the evaluated string comes from user input, attackers can inject code ` +
          `that executes with the application's full privileges.`,
        fix: 'Replace eval/Function with structured alternatives: ' +
          'JS: use object lookup or switch/case. Python: use dict dispatch. PHP: use match/array mapping. ' +
          'For math expressions, use a safe parser library instead of eval.',
      });
    }
  }

  const evalNodes = map.nodes.filter(n => {
    const code = n.analysis_snapshot || (n.analysis_snapshot || n.code_snapshot);
    return (EVAL_VAR_PHP.test(code) || EXEC_VAR_PY.test(code) || DYNAMIC_VAR_EVAL.test(code) ||
            FUNCTION_CONSTRUCTOR_CS.test(code) || PY_ATTR_INPUT.test(code)) &&
           !SAFE_EVAL.test(stripComments(code)) && !ALLOWLIST_CHECK.test(stripComments(code));
  });

  for (const src of ingress) {
    for (const ev of evalNodes) {
      if (src.id === ev.id) continue;
      if (findings.some(f => f.sink.id === ev.id)) continue;
      if (hasTaintedPathWithoutControl(map, src.id, ev.id)) {
        findings.push({
          source: nodeRef(src), sink: nodeRef(ev),
          missing: 'CONTROL (sanitize/validate input before dynamic evaluation)',
          severity: 'critical',
          description: `User input from ${src.label} flows to dynamic evaluation at ${ev.label}. ` +
            `The eval/exec/Function call processes user-controlled data as code, enabling ` +
            `arbitrary variable manipulation and code execution.`,
          fix: 'Remove dynamic evaluation. Use structured alternatives (dictionary lookup, switch/case, allowlist). ' +
            'If eval is absolutely necessary, sandbox it completely and validate input against a strict grammar.',
        });
      }
    }
  }

  return { cwe: 'CWE-627', name: 'Dynamic Variable Evaluation', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-636: Not Failing Securely (Failing Open)
//
// When a security mechanism encounters an error or exception, it allows the
// operation to proceed instead of denying it. Auth checks that catch exceptions
// and return true, firewall rules that default to allow, access control that
// falls through to grant on error. The security decision defaults to PERMIT
// when it should default to DENY.
// ---------------------------------------------------------------------------

function verifyCWE636(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const AUTH_FUNCTION = /\b(isAuth|isAdmin|checkAuth|verifyAuth|authenticate|authorize|checkPermission|hasPermission|hasRole|isAllowed|canAccess|validateToken|verifyToken|checkAccess|requireAuth|ensureAuth|isLoggedIn|checkRole|verifySession|isAuthorized|checkCredentials|validateSession)\b/i;
  const SECURITY_CHECK = /\b(verify|validate|authenticate|authorize|check.*(?:auth|perm|role|access|token|session|cred)|is.*(?:auth|admin|valid|allowed|permitted))\b/i;

  const CATCH_RETURN_TRUE = /catch\s*(?:\(\s*\w+\s*\))?\s*\{[^}]*(?:return\s+true|return\s+null|return\s+undefined|return\s*;|pass\b|continue\b)/i;
  const CATCH_ALLOW = /catch\s*(?:\(\s*\w+\s*\))?\s*\{[^}]*(?:return\s+true|isAuth\w*\s*=\s*true|authenticated\s*=\s*true|authorized\s*=\s*true|allowed\s*=\s*true|granted\s*=\s*true|valid\s*=\s*true)/i;
  const EMPTY_CATCH = /catch\s*(?:\(\s*\w+\s*\))?\s*\{\s*\}/;
  const PY_EXCEPT_PASS = /except\s*(?:\w+\s*)?:\s*(?:\n\s*)?(?:pass|return\s+True|return\s+None)\b/i;

  const DEFAULT_ALLOW = /(?:(?:let|var|const|bool|boolean)\s+)?(?:isAuth\w*|authenticated|authorized|allowed|permitted|granted|hasAccess|valid)\s*(?::\s*\w+\s*)?=\s*(?:true|True|TRUE|1)\b/i;

  const SAFE_FAIL = /\b(return\s+false|throw\s+|raise\s+|deny|reject|forbidden|unauthorized|return\s+null.*(?:if|unless|when)|return\s+403|return\s+401|res\.status\s*\(\s*(?:401|403)|HttpStatus\.(?:UNAUTHORIZED|FORBIDDEN))\b/i;
  const DEFAULT_DENY = /(?:(?:let|var|const|bool|boolean)\s+)?(?:isAuth\w*|authenticated|authorized|allowed|permitted|granted|hasAccess|valid)\s*(?::\s*\w+\s*)?=\s*(?:false|False|FALSE|0)\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);

    if ((AUTH_FUNCTION.test(code) || SECURITY_CHECK.test(code)) &&
        (CATCH_ALLOW.test(code) || (EMPTY_CATCH.test(code) && !SAFE_FAIL.test(code)))) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (catch block in security check must deny access, not allow it)',
        severity: 'critical',
        description: `${node.label} has a security check that catches exceptions and defaults to ALLOW. ` +
          `If the auth/validation mechanism fails (DB down, token parse error, network timeout), ` +
          `the catch block returns true/null/undefined, granting access. An attacker can trigger ` +
          `the error condition to bypass authentication entirely.`,
        fix: 'Security checks MUST fail closed: catch blocks should return false, throw, or deny access. ' +
          'Pattern: try { return verifyToken(token); } catch (e) { return false; } — never catch and allow.',
      });
      continue;
    }

    if (PY_EXCEPT_PASS.test(code) && SECURITY_CHECK.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (except clause in security check must deny access)',
        severity: 'critical',
        description: `${node.label} has a Python security check with "except: pass" or "except: return True". ` +
          `When the security check raises an exception (connection error, parse error, etc.), the code ` +
          `silently continues or returns True, effectively granting access on failure.`,
        fix: 'Replace "except: pass" with "except: return False" or "except: raise". ' +
          'Security checks must fail closed. Log the error for debugging but always deny access on exception.',
      });
      continue;
    }

    if (DEFAULT_ALLOW.test(code) && !DEFAULT_DENY.test(code)) {
      const isScopeSecurityCheck = SECURITY_CHECK.test(code) || AUTH_FUNCTION.test(code);
      const hasConditionalDeny = /(?:if|else|unless|when)[\s\S]*?(?:=\s*false|=\s*False|=\s*FALSE|=\s*0)\b/i.test(code);

      if (isScopeSecurityCheck && !hasConditionalDeny) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (initialize security variables to false/deny, set true only on verified success)',
          severity: 'high',
          description: `${node.label} initializes a security decision variable to true/allow. If the code ` +
            `that should set it to false is skipped (early return, exception, logic error), access is ` +
            `granted by default. This is the "fail open" anti-pattern.`,
          fix: 'Initialize security variables to false/deny: let isAuthorized = false; ' +
            'Set to true ONLY after positive verification: if (validToken) isAuthorized = true. ' +
            'This ensures any unexpected code path defaults to deny.',
        });
        continue;
      }
    }
  }

  const authNodes = nodesOfType(map, 'AUTH');
  const controlNodes = nodesOfType(map, 'CONTROL');
  for (const node of [...authNodes, ...controlNodes]) {
    const code = stripComments(node.analysis_snapshot || node.analysis_snapshot || node.code_snapshot);
    if (findings.some(f => f.source.id === node.id)) continue;

    const hasTryCatch = /\b(try\s*\{|try:|begin\b|rescue\b|except\b)/i.test(code);
    if (!hasTryCatch) continue;

    const hasSafeFail = SAFE_FAIL.test(code);
    const hasCatchAllow = CATCH_RETURN_TRUE.test(code) || EMPTY_CATCH.test(code) || PY_EXCEPT_PASS.test(code);

    if (hasCatchAllow && !hasSafeFail) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (error handler in security gate must deny access)',
        severity: 'high',
        description: `AUTH/CONTROL node ${node.label} has error handling that does not explicitly deny access. ` +
          `When this security gate throws an exception, the error handler may allow the request through. ` +
          `Security mechanisms must fail closed — deny access on any unexpected condition.`,
        fix: 'Add explicit deny in all catch/except blocks: return false, throw an auth error, or redirect to login. ' +
          'Never use empty catch blocks or "except: pass" in security-critical code paths.',
      });
    }
  }

  return { cwe: 'CWE-636', name: 'Not Failing Securely (Failing Open)', holds: findings.length === 0, findings };
}

/**
 * CWE-477: Use of Obsolete Function
 * Source scan for deprecated Java API calls. These APIs have known issues:
 * - Thread.stop/suspend/resume — unsafe thread manipulation
 * - Runtime.runFinalizersOnExit — finalization is broken by design
 * - DataInputStream.readLine — mishandles Unicode (deprecated since JDK 1.1)
 * - Date.parse — superseded by DateFormat.parse
 * - String.getBytes(int,int,byte[],int) — mishandles non-ASCII (deprecated since JDK 1.1)
 * - URLEncoder.encode(String) — uses platform default encoding, not UTF-8
 */
function verifyCWE477(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Deprecated Java APIs: method name + context pattern + replacement guidance
  const OBSOLETE_APIS: Array<{ pattern: RegExp; name: string; fix: string }> = [
    { pattern: /\bThread\s*\.\s*stop\s*\(/, name: 'Thread.stop()', fix: 'Use Thread.interrupt() and cooperative cancellation instead of Thread.stop().' },
    { pattern: /\bThread\s*\.\s*suspend\s*\(/, name: 'Thread.suspend()', fix: 'Use wait/notify or Lock/Condition instead of Thread.suspend().' },
    { pattern: /\bThread\s*\.\s*resume\s*\(/, name: 'Thread.resume()', fix: 'Use wait/notify or Lock/Condition instead of Thread.resume().' },
    { pattern: /\bRuntime\s*\.\s*runFinalizersOnExit\s*\(/, name: 'Runtime.runFinalizersOnExit()', fix: 'Use shutdown hooks (Runtime.addShutdownHook) or try-with-resources instead.' },
    { pattern: /\bSystem\s*\.\s*runFinalizersOnExit\s*\(/, name: 'System.runFinalizersOnExit()', fix: 'Use shutdown hooks (Runtime.addShutdownHook) or try-with-resources instead.' },
    { pattern: /\bDataInputStream\b[\s\S]*?\.readLine\s*\(/, name: 'DataInputStream.readLine()', fix: 'Use BufferedReader.readLine() instead of DataInputStream.readLine(). The deprecated method incorrectly converts bytes to characters.' },
    { pattern: /\bDate\s*\.\s*parse\s*\(/, name: 'Date.parse()', fix: 'Use DateFormat.parse() or java.time.LocalDate.parse() instead of the deprecated Date.parse().' },
    { pattern: /\.getBytes\s*\(\s*\d+\s*,/, name: 'String.getBytes(int,int,byte[],int)', fix: 'Use String.getBytes(charset) instead of the deprecated 4-argument getBytes. Specify charset explicitly (e.g., "UTF-8").' },
    { pattern: /\bURLEncoder\s*\.\s*encode\s*\(\s*[^,)]+\)/, name: 'URLEncoder.encode(String)', fix: 'Use URLEncoder.encode(s, "UTF-8") instead of the single-argument form, which uses platform default encoding.' },
  ];

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.code_snapshot);

    for (const api of OBSOLETE_APIS) {
      if (api.pattern.test(code)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: `STRUCTURAL (replace obsolete API: ${api.name})`,
          severity: 'medium',
          description: `Obsolete function ${api.name} used at ${node.label}. ` +
            `Deprecated APIs may have known bugs, security vulnerabilities, or undefined behavior.`,
          fix: api.fix,
        });
      }
    }
  }

  return { cwe: 'CWE-477', name: 'Use of Obsolete Function', holds: findings.length === 0, findings };
}

/* REMOVED: verifyCWE549 — now in sensitive-data.ts */

// ---------------------------------------------------------------------------
// CWE-111: Direct Use of Unsafe JNI
// ---------------------------------------------------------------------------
/**
 * CWE-111: Direct Use of Unsafe JNI
 * UPGRADED — hand-written with specific detection for unsafe JNI usage.
 *
 * Pattern: Java code declares `native` methods (JNI interface) and passes
 * user-controlled input to them without validation. The native C/C++ code
 * cannot perform Java-style bounds checking, so buffer overflows, format
 * string attacks, and memory corruption are possible.
 *
 * Two detection paths:
 *   1. `native` method declared + user input flows to a call of that method
 *      without validation (bounds check, length limit, allowlist)
 *   2. User input flows to System.loadLibrary() — attacker controls which
 *      native library gets loaded
 *
 * Safe patterns:
 *   - Input validation/bounds checking before native call
 *   - Allowlist of permitted values
 *   - Hardcoded library name in System.loadLibrary (not tainted)
 */
function verifyCWE111(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // --- Detection path 1: native method + tainted call to it ---
  // Find nodes whose code_snapshot contains a `native` method declaration
  const NATIVE_DECL_RE = /\bnative\s+\w[\w<>\[\], ]*\s+(\w+)\s*\(/;

  // Collect all native method names declared in the codebase
  const nativeMethodNames = new Set<string>();
  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.code_snapshot);
    const match = NATIVE_DECL_RE.exec(code);
    if (match) {
      nativeMethodNames.add(match[1]);
    }
  }

  if (nativeMethodNames.size > 0 && ingress.length > 0) {
    // Find call sites of native methods — any node whose code calls a native method
    for (const node of map.nodes) {
      const code = stripComments(node.analysis_snapshot || node.code_snapshot);
      for (const methodName of nativeMethodNames) {
        // Match calls like: test(stringLine, intNumber) or this.test(x)
        const callPattern = new RegExp(`\\b${methodName}\\s*\\(`);
        // But skip the native declaration itself
        const declPattern = new RegExp(`\\bnative\\s+.*\\b${methodName}\\s*\\(`);
        if (callPattern.test(code) && !declPattern.test(code)) {
          // This node calls a native method — check if any INGRESS reaches it
          for (const src of ingress) {
            if (hasTaintedPathWithoutControl(map, src.id, node.id) || sinkHasTaintedDataIn(map, node.id)) {
              // Check scope for validation
              const scopeSnapshots = getContainingScopeSnapshots(map, node.id);
              const combinedScope = stripComments(scopeSnapshots.join('\n') || code);
              const isSafe = /\bvalidate\s*\(|\bboundsCheck\s*\(|\bif\s*\(\s*\w+\s*(?:<=?|>=?|<|>)\s*\d|\blength\s*(?:<=?|>=?)\s*\d|\bMath\.min\s*\(|\bMath\.max\s*\(|\ballowlist\b|\bwhitelist\b/i.test(combinedScope);

              if (!isSafe) {
                findings.push({
                  source: nodeRef(src),
                  sink: nodeRef(node),
                  missing: 'CONTROL (input validation before JNI native call)',
                  severity: 'high',
                  description: `User input from ${src.label} flows to JNI native method ${methodName}() at ${node.label} without validation. ` +
                    `Native code cannot perform Java bounds checking — buffer overflows, format string attacks, ` +
                    `and memory corruption are possible.`,
                  fix: 'Validate all data before passing to JNI native methods. Check string lengths, ' +
                    'integer ranges, and array bounds. Use an allowlist of permitted values where possible. ' +
                    'Consider wrapping JNI calls in a safe Java API that validates inputs.',
                });
                break; // One finding per sink per native method
              }
            }
          }
        }
      }
    }
  }

  // --- Detection path 2: tainted System.loadLibrary() ---
  const LOAD_LIBRARY_RE = /\bSystem\s*\.\s*loadLibrary\s*\(/;
  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.code_snapshot);
    if (LOAD_LIBRARY_RE.test(code)) {
      for (const src of ingress) {
        if (hasTaintedPathWithoutControl(map, src.id, node.id) || sinkHasTaintedDataIn(map, node.id)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(node),
            missing: 'CONTROL (library name validation — use hardcoded name or allowlist)',
            severity: 'critical',
            description: `User input from ${src.label} controls the library name in System.loadLibrary() at ${node.label}. ` +
              `An attacker can load arbitrary native libraries, gaining code execution.`,
            fix: 'Never pass user input to System.loadLibrary(). Use a hardcoded library name or ' +
              'validate against a strict allowlist of permitted library names.',
          });
          break;
        }
      }
    }
  }

  // --- Detection path 3: structural — native decl + any INGRESS in same scope ---
  // If we found native methods but no taint path (mapper may not create DATA_FLOW edges),
  // check if native method calls share function scope with user input reads
  if (findings.length === 0 && nativeMethodNames.size > 0 && ingress.length > 0) {
    for (const node of map.nodes) {
      const code = stripComments(node.analysis_snapshot || node.code_snapshot);
      for (const methodName of nativeMethodNames) {
        const callPattern = new RegExp(`\\b${methodName}\\s*\\(`);
        const declPattern = new RegExp(`\\bnative\\s+.*\\b${methodName}\\s*\\(`);
        if (callPattern.test(code) && !declPattern.test(code)) {
          for (const src of ingress) {
            if (sharesFunctionScope(map, src.id, node.id)) {
              const scopeSnapshots = getContainingScopeSnapshots(map, node.id);
              const combinedScope = stripComments(scopeSnapshots.join('\n') || code);
              const isSafe = /\bvalidate\s*\(|\bboundsCheck\s*\(|\bif\s*\(\s*\w+\s*(?:<=?|>=?|<|>)\s*\d|\blength\s*(?:<=?|>=?)\s*\d|\bMath\.min\s*\(|\bMath\.max\s*\(|\ballowlist\b|\bwhitelist\b/i.test(combinedScope);

              if (!isSafe) {
                findings.push({
                  source: nodeRef(src),
                  sink: nodeRef(node),
                  missing: 'CONTROL (input validation before JNI native call)',
                  severity: 'high',
                  description: `User input from ${src.label} is in scope with JNI native method ${methodName}() call at ${node.label}. ` +
                    `Native code cannot perform Java bounds checking — buffer overflows, format string attacks, ` +
                    `and memory corruption are possible when user input reaches native methods.`,
                  fix: 'Validate all data before passing to JNI native methods. Check string lengths, ' +
                    'integer ranges, and array bounds. Use an allowlist of permitted values where possible.',
                });
                break;
              }
            }
          }
        }
      }
    }
  }

  return { cwe: 'CWE-111', name: 'Direct Use of Unsafe JNI', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// CWE-114: Process Control
// ---------------------------------------------------------------------------
/**
 * CWE-114: Process Control
 * UPGRADED — hand-written with specific detection for unsafe process/library loading.
 *
 * Pattern: Code loads native libraries or executes processes in ways that an
 * attacker can control:
 *   1. System.loadLibrary(name) — loads by name from java.library.path; attacker
 *      can plant a malicious DLL/so in a directory on the search path
 *   2. System.load(taintedPath) — attacker controls the full path to a library
 *   3. Runtime.exec(taintedCmd) — attacker controls process execution
 *
 * The Juliet pattern: System.loadLibrary("test.dll") is BAD because it uses
 * relative name resolution. System.load("/absolute/path/test.dll") is GOOD
 * because it uses an absolute path that the attacker cannot manipulate.
 *
 * Safe patterns:
 *   - System.load() with hardcoded absolute path
 *   - Allowlist validation of library name or command
 *   - SecurityManager restricting library loading
 */
function verifyCWE114(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  const LOAD_LIBRARY_RE = /\bSystem\s*\.\s*loadLibrary\s*\(/;
  const SYSTEM_LOAD_RE = /\bSystem\s*\.\s*load\s*\(/;
  const RUNTIME_EXEC_RE = /\bRuntime\s*\..*\bexec\s*\(/;
  const PROCESS_BUILDER_RE = /\bnew\s+ProcessBuilder\s*\(/;

  // Safe patterns for CWE-114
  const ABSOLUTE_PATH_RE = /System\s*\.\s*load\s*\(\s*(?:root\s*\+|"\/|"[A-Z]:\\|['"]\/home|['"]\/usr|['"]\/opt|['"]C:\\)/;
  const SECURITY_MANAGER_RE = /\bSecurityManager\b|\bcheckLink\b|\bcheckExec\b/;
  const ALLOWLIST_RE = /\ballowlist\b|\bwhitelist\b|\bvalidat(?:e|ed|ion)\s*\(|\bpermitted\b|\bapproved\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.analysis_snapshot || node.code_snapshot);
    const scopeSnapshots = getContainingScopeSnapshots(map, node.id);
    const combinedScope = stripComments(scopeSnapshots.join('\n') || code);

    // --- Detection 1: System.loadLibrary() — relative name, search-path based ---
    if (LOAD_LIBRARY_RE.test(code)) {
      // Check if there's a SecurityManager or allowlist in scope
      if (!SECURITY_MANAGER_RE.test(combinedScope) && !ALLOWLIST_RE.test(combinedScope)) {
        // System.loadLibrary is inherently risky — relative resolution
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (use System.load() with absolute path instead of System.loadLibrary())',
          severity: 'medium',
          description: `System.loadLibrary() at ${node.label} loads a native library by name using java.library.path search. ` +
            `An attacker who can influence the search path or plant a DLL in a searched directory ` +
            `can hijack the library loading (DLL search-order hijacking).`,
          fix: 'Use System.load() with an absolute path to the library instead of System.loadLibrary(). ' +
            'Example: System.load("/opt/myapp/libs/mylib.so") instead of System.loadLibrary("mylib"). ' +
            'If System.loadLibrary() is unavoidable, restrict java.library.path and use a SecurityManager.',
        });
      }
    }

    // --- Detection 2: System.load() with tainted path ---
    if (SYSTEM_LOAD_RE.test(code) && !LOAD_LIBRARY_RE.test(code)) {
      // System.load() is safe IF the path is hardcoded/absolute
      if (ABSOLUTE_PATH_RE.test(code)) {
        continue; // Safe — hardcoded absolute path
      }
      // Check if tainted input flows to this node
      for (const src of ingress) {
        if (hasTaintedPathWithoutControl(map, src.id, node.id) || sinkHasTaintedDataIn(map, node.id)) {
          if (!ALLOWLIST_RE.test(combinedScope)) {
            findings.push({
              source: nodeRef(src),
              sink: nodeRef(node),
              missing: 'CONTROL (path validation for System.load())',
              severity: 'critical',
              description: `User input from ${src.label} controls the library path in System.load() at ${node.label}. ` +
                `An attacker can load any native library on disk, gaining arbitrary code execution.`,
              fix: 'Never pass user input to System.load(). Use a hardcoded absolute path or ' +
                'validate the path against a strict allowlist of permitted library paths.',
            });
            break;
          }
        }
      }
    }

    // --- Detection 3: Runtime.exec() or ProcessBuilder with tainted input ---
    if (RUNTIME_EXEC_RE.test(code) || PROCESS_BUILDER_RE.test(code)) {
      for (const src of ingress) {
        if (hasTaintedPathWithoutControl(map, src.id, node.id) || sinkHasTaintedDataIn(map, node.id)) {
          if (!ALLOWLIST_RE.test(combinedScope)) {
            findings.push({
              source: nodeRef(src),
              sink: nodeRef(node),
              missing: 'CONTROL (process execution validation)',
              severity: 'critical',
              description: `User input from ${src.label} controls process execution at ${node.label}. ` +
                `An attacker can execute arbitrary processes on the system.`,
              fix: 'Never pass user input to Runtime.exec() or ProcessBuilder. Use a strict allowlist ' +
                'of permitted commands. Consider using a ProcessBuilder with a fixed command array ' +
                'instead of string concatenation.',
            });
            break;
          }
        }
      }
    }
  }

  return { cwe: 'CWE-114', name: 'Process Control', holds: findings.length === 0, findings };
}

/**
 * CWE-15: External Control of System or Configuration Setting
 * Pattern: INGRESS → system/config modification API without CONTROL(validation)
 * Property: External input never directly modifies system or configuration settings.
 *
 * Detects tainted data flowing from external sources (sockets, HTTP requests,
 * user input) into APIs that modify system-level configuration:
 *   Java:   System.setProperty(), Connection.setCatalog(), Connection.setSchema(),
 *           Properties.setProperty(), System.setOut(), System.setErr()
 *   C/C++:  putenv(), setenv()
 *   Python: os.environ[], os.putenv()
 *   JS/TS:  process.env assignment
 *
 * The Juliet pattern: socket.read() → dbConnection.setCatalog(data)
 * — attacker controls which database catalog is active.
 */
function verifyCWE15(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Config/system modification sink patterns across languages
  const configSinkRe = /\b(System\s*\.\s*setProperty|setProperty\s*\(|setCatalog\s*\(|setSchema\s*\(|putenv\s*\(|setenv\s*\(|os\s*\.\s*environ\s*\[|os\s*\.\s*putenv\s*\(|process\s*\.\s*env\s*\[|Properties\s*\.\s*setProperty|System\s*\.\s*setOut|System\s*\.\s*setErr|Runtime\s*\.\s*getRuntime\s*\(\s*\)\s*\.\s*exec)\b/i;

  const configSinks = map.nodes.filter(n => {
    const code = n.analysis_snapshot || n.code_snapshot;
    return configSinkRe.test(code);
  });

  const safeConfigRe = /\bvalidate\s*\(|\ballowlist\b|\bwhitelist\b|\ballowed\w*\s*\.\s*(?:contains|includes|has|indexOf)\b|\bPattern\s*\.\s*matches?\b|\bswitch\s*\(|\bcase\s+['"]/i;

  for (const src of ingress) {
    for (const sink of configSinks) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id) || sinkHasTaintedDataIn(map, sink.id)) {
        const scopeSnaps15 = getContainingScopeSnapshots(map, sink.id);
        const scope15 = stripComments(scopeSnaps15.join('\n') || sink.analysis_snapshot || sink.code_snapshot);
        if (!safeConfigRe.test(scope15)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (input validation before system/configuration modification)',
            severity: 'high',
            description: `External input from ${src.label} flows to system/configuration setting at ${sink.label} without validation. ` +
              `An attacker can modify system properties, database catalogs, environment variables, or runtime configuration.`,
            fix: 'Never pass unsanitized external input to system configuration APIs. ' +
              'Use an allowlist of permitted configuration values. ' +
              'Validate against a strict pattern (e.g., switch/case or Set.has()) before calling setCatalog(), setProperty(), putenv(), etc.',
          });
        }
      }
    }
  }

  // Phase 2: Source-line scan fallback
  if (findings.length === 0 && map.source_code && ingress.length > 0) {
    const srcLines = map.source_code.split('\n');
    const cfgCallRe = /\b(?:setCatalog|setSchema|setProperty|putenv|setenv|os\.environ)\s*\(/i;
    const hardcodedRe = /\b(?:setCatalog|setSchema|setProperty|putenv|setenv)\s*\(\s*["'][^"']*["']\s*[,)]/i;

    for (let li = 0; li < srcLines.length; li++) {
      const ln = srcLines[li]!;
      const tr = ln.trim();
      if (!tr || tr.startsWith('//') || tr.startsWith('*') || tr.startsWith('/*')) continue;

      if (cfgCallRe.test(ln) && !hardcodedRe.test(ln)) {
        // Extract the variable name used as argument to the config API
        const argM15 = /\b(?:setCatalog|setSchema|setProperty|putenv|setenv)\s*\(\s*(\w+)\s*[,)]/i.exec(ln);
        const argV15 = argM15 ? argM15[1] : null;

        // Check if the variable was assigned a hardcoded literal in the lookback scope
        let isHardcoded15 = false;
        if (argV15) {
          const escV = argV15.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          const hardAssign = new RegExp(`\\b${escV}\\s*=\\s*(?:["']|\\d+\\s*;)`);
          const taintAssign = new RegExp(`\\b${escV}\\s*=.*(?:readLine|getParameter|getInput|parseInt|read\\()`);
          for (let j = li - 1; j >= Math.max(0, li - 30); j--) {
            const prev = srcLines[j]!.trim();
            if (hardAssign.test(prev)) { isHardcoded15 = true; break; }
            if (taintAssign.test(prev)) break;
          }
        }

        if (!isHardcoded15) {
          const cs = Math.max(0, li - 20);
          const ce = Math.min(srcLines.length, li + 5);
          const ctx = srcLines.slice(cs, ce).join('\n');
          if (!safeConfigRe.test(ctx)) {
            findings.push({
              source: nodeRef(ingress[0]!),
              sink: { id: `line-${li + 1}`, label: `config modification (line ${li + 1})`, line: li + 1, code: tr.slice(0, 200) },
              missing: 'CONTROL (input validation before system/configuration modification)',
              severity: 'high',
              description: `System/configuration setting modified with a variable at line ${li + 1}: "${tr.slice(0, 100)}". ` +
                `If this value originates from external input, an attacker can control system configuration.`,
              fix: 'Validate the value against an allowlist before passing it to configuration APIs.',
            });
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-15',
    name: 'External Control of System or Configuration Setting',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-129: Improper Validation of Array Index
 * Pattern: External input used as array index with incomplete bounds validation
 * Property: All externally-sourced array indices are validated with BOTH
 *           lower bound (>= 0) AND upper bound (< array.length) checks.
 *
 * The Juliet vulnerable pattern:
 *   data = Integer.parseInt(socketInput);
 *   if (data < array.length) { array[data] }  // missing >= 0 check
 *
 * The safe pattern:
 *   if (data >= 0 && data < array.length) { array[data] }
 */
function verifyCWE129(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Phase 1: Graph-based detection
  const arrAccessRe = /\[\s*\w+\s*\]|\barray\s*\[|\blist\s*\[|\barr\s*\[|\bdata\s*\[|\bbuffer\s*\[|\belements?\s*\[/i;
  const arrNodes = map.nodes.filter(n => {
    const code = n.analysis_snapshot || n.code_snapshot;
    return arrAccessRe.test(code) && !/\[\s*['"`]/.test(code);
  });

  const fullBoundsRe = />=\s*0\s*&&[^;]*<\s*\w+\.length|>=\s*0\s*&&[^;]*<\s*\w+\s*\)|0\s*<=\s*\w+\s*&&|\bMath\.max\s*\(\s*0\s*,|\bMath\.min\s*\(|\bclamp\s*\(|\bbetween\s*\(|\binRange\s*\(/i;

  for (const src of ingress) {
    for (const sink of arrNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id) || sinkHasTaintedDataIn(map, sink.id)) {
        const ss129 = getContainingScopeSnapshots(map, sink.id);
        const sc129 = stripComments(ss129.join('\n') || sink.analysis_snapshot || sink.code_snapshot);
        if (!fullBoundsRe.test(sc129)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (complete bounds validation: both >= 0 AND < array.length)',
            severity: 'high',
            description: `External input from ${src.label} is used as array index at ${sink.label} without complete bounds validation. ` +
              `A negative value bypasses an upper-bound-only check and causes ArrayIndexOutOfBoundsException.`,
            fix: 'Always validate array indices with BOTH bounds: if (index >= 0 && index < array.length). ' +
              'An upper-bound check alone does NOT prevent negative indices.',
          });
        }
      }
    }
  }

  // Phase 2: Source-line scanning for the classic Juliet pattern
  if (map.source_code) {
    const sl129 = map.source_code.split('\n');
    const pvars = new Set<string>();
    const parseRe = /\b(\w+)\s*=\s*(?:Integer\s*\.\s*parseInt|parseInt|Number\s*\(|int\s*\(|float\s*\(|Double\s*\.\s*parseDouble|Long\s*\.\s*parseLong|Short\s*\.\s*parseShort)\b/;
    for (const l of sl129) {
      const pm = parseRe.exec(l);
      if (pm) pvars.add(pm[1]!);
    }

    if (pvars.size > 0) {
      for (let li = 0; li < sl129.length; li++) {
        const ln = sl129[li]!;
        const tr = ln.trim();
        if (!tr || tr.startsWith('//') || tr.startsWith('*') || tr.startsWith('/*')) continue;

        for (const vn of pvars) {
          const ev = vn.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          const upRe = new RegExp(`if\\s*\\(\\s*${ev}\\s*<\\s*\\w+\\.length\\b`);
          if (!upRe.test(ln)) continue;

          const cs = Math.max(0, li - 5);
          const ce = Math.min(sl129.length, li + 1);
          const ctx = sl129.slice(cs, ce).join('\n');
          const loRe = new RegExp(`${ev}\\s*>=\\s*0|0\\s*<=\\s*${ev}|Math\\.max\\s*\\(\\s*0|Math\\.min\\s*\\(`);
          if (loRe.test(ctx)) continue;

          // Check if the variable was reassigned a hardcoded literal in the lookback
          // (e.g., data = 2 in goodG2B means it's NOT tainted in this scope)
          let isHardcoded129 = false;
          const hardLitRe = new RegExp(`\\b${ev}\\s*=\\s*\\d+\\s*;`);
          const hardStrRe = new RegExp(`\\b${ev}\\s*=\\s*["']`);
          for (let j = li - 1; j >= Math.max(0, li - 20); j--) {
            const prev129 = sl129[j]!.trim();
            if (hardLitRe.test(prev129) || hardStrRe.test(prev129)) { isHardcoded129 = true; break; }
            // If we see a parseInt/readLine assignment, it's tainted — stop looking
            if (new RegExp(`\\b${ev}\\s*=.*(?:parseInt|readLine|getParameter|getInput)`).test(prev129)) break;
          }
          if (isHardcoded129) continue;

          const dup = findings.some(f => f.sink.line !== undefined && Math.abs(f.sink.line - (li + 1)) <= 3);
          if (dup) continue;

          const sn = ingress.length > 0 ? ingress[0]! : findNearestNode(map, li + 1);
          if (sn) {
            findings.push({
              source: nodeRef(sn),
              sink: { id: `line-${li + 1}`, label: `array bounds check (line ${li + 1})`, line: li + 1, code: tr.slice(0, 200) },
              missing: 'CONTROL (lower bound check: index >= 0 missing before array access)',
              severity: 'high',
              description: `Array index "${vn}" has only an upper-bound check at line ${li + 1}: "${tr.slice(0, 80)}". ` +
                `The lower-bound check (>= 0) is missing. Negative values pass and cause ArrayIndexOutOfBoundsException.`,
              fix: `Add a lower-bound check: if (${vn} >= 0 && ${vn} < array.length). Both bounds must be checked.`,
            });
          }
        }
      }
    }

    // Phase 3: Detect completely unvalidated array access (no bounds check at all).
    // Phase 2 catches "upper-bound-only" (check_max). Phase 3 catches "no check at all"
    // (no_check), which is arguably the more dangerous variant.
    if (pvars.size > 0) {
      for (let li = 0; li < sl129.length; li++) {
        const ln3 = sl129[li]!;
        const tr3 = ln3.trim();
        if (!tr3 || tr3.startsWith('//') || tr3.startsWith('*') || tr3.startsWith('/*')) continue;

        for (const vn of pvars) {
          const ev3 = vn.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          // Match array[var] usage
          const arrUseRe = new RegExp(`\\[\\s*${ev3}\\s*\\]`);
          if (!arrUseRe.test(ln3)) continue;

          // Check: is there ANY bounds check within 10 lines above?
          const ctxStart = Math.max(0, li - 10);
          const ctxEnd = Math.min(sl129.length, li + 1);
          const ctx3 = sl129.slice(ctxStart, ctxEnd).join('\n');
          const anyBoundsRe3 = new RegExp(
            `${ev3}\\s*<\\s*\\w+\\.length|` +
            `${ev3}\\s*>=\\s*0|` +
            `0\\s*<=\\s*${ev3}|` +
            `${ev3}\\s*>\\s*0|` +
            `Math\\.max\\s*\\(\\s*0|` +
            `Math\\.min\\s*\\(`
          );
          if (anyBoundsRe3.test(ctx3)) continue;

          // Hardcoded check: skip if variable was assigned a literal (goodG2B pattern)
          let isHardcoded3 = false;
          const hardLitRe3 = new RegExp(`\\b${ev3}\\s*=\\s*\\d+\\s*;`);
          for (let j = li - 1; j >= Math.max(0, li - 20); j--) {
            if (hardLitRe3.test(sl129[j]!.trim())) { isHardcoded3 = true; break; }
            if (new RegExp(`\\b${ev3}\\s*=.*(?:parseInt|readLine|getParameter|getInput)`).test(sl129[j]!.trim())) break;
          }
          if (isHardcoded3) continue;

          // Dedup against existing findings from Phase 1 or Phase 2
          const dup3 = findings.some(f => f.sink.line !== undefined && Math.abs(f.sink.line - (li + 1)) <= 3);
          if (dup3) continue;

          const sn3 = ingress.length > 0 ? ingress[0]! : findNearestNode(map, li + 1);
          if (sn3) {
            findings.push({
              source: nodeRef(sn3),
              sink: { id: `line-${li + 1}`, label: `unvalidated array access (line ${li + 1})`, line: li + 1, code: tr3.slice(0, 200) },
              missing: 'CONTROL (no bounds validation before array access)',
              severity: 'high',
              description: `Array index "${vn}" from external input is used at line ${li + 1}: "${tr3.slice(0, 80)}" with NO bounds validation. ` +
                `Any value including negative numbers will be accepted, causing ArrayIndexOutOfBoundsException.`,
              fix: `Add bounds validation: if (${vn} >= 0 && ${vn} < array.length) before accessing array[${vn}].`,
            });
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-129',
    name: 'Improper Validation of Array Index',
    holds: findings.length === 0,
    findings,
  };
}

